-- 拜访规则
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('6f56fed3-d54a-11e9-b9aa-0298a739dec0', '5299a45e-7408-11e6-bbe0-5cc5d4b571d2', '拜访验证规则', '拜访验证规则', 'trigger', 'from orionbase.common import models\nfrom orionbase.common import models\nfrom django.utils.timezone import utc, localtime\nimport datetime\n\ncalls = models.Calls.objects.filter(deleted=delete_types.is_not_delete, account__id=instance.account.id, call_date=instance.call_date, owner__id=instance.owner.id)\ncall = calls[0] if calls else None\n\nif call and call.id != instance.id:\n    message = \'每人只可以在同一天内对同一医生拜访一次\'\n    raise create_validation_trigger_rule_errors(message)\n\nnow = datetime.datetime.now()\ndate_now = now.date()\ncalls = models.Calls.objects.filter(deleted=delete_types.is_not_delete, id=instance.id)\ncall = calls[0] if calls else None\nif type(instance.call_date) == datetime.date:\n    start_time = instance.call_date\nelse:\n    start_time = datetime.datetime.strptime(instance.call_date, \'%Y-%m-%d\').date()\n\nif instance.state.name == \'finished\' and (not call or call.state.name == \'unfinished\'):\n    if start_time > date_now:\n        message = \'不能完成未来的拜访\'\n        raise create_validation_trigger_rule_errors(message)', '', '0', '1', '2019-09-16 11:22:20', '1', '2019-09-12 10:51:59', 'pre_save', '1', 'custom', 'call_validation');

